import React from 'react';
import type { ColorPickerBaseProps } from '../type';
import { ColorPickerProvider, useColorPicker } from '../ColorPickerContext';
import { Palette } from './Palette';

import '../style';

/**
 * @deprecated
 * 请使用 `PaletteColorPicker`，后续版本会对 `ColorPalette` 组件改名
 */
export type SketchProps = ColorPickerBaseProps;

export const ColorPalette: React.FC<SketchProps> = props => {
  const { className, style } = props;
  const colorPickerCtx = useColorPicker(props);

  return (
    <ColorPickerProvider value={colorPickerCtx}>
      <Palette {...{ className, style }} />
    </ColorPickerProvider>
  );
};

/**
 * @public
 * @docgen
 * @privateRemarks
 * New alias
 */
export type PaletteColorPickerProps = SketchProps;
export const PaletteColorPicker = ColorPalette;
